#!/bin/bash
# Generated by Fablo (poc/fabric-x-integration)
# Startup script for a Fabric-X network
#
# Startup order matters:
# 1. Generate crypto material (must include SC hostname for sidecar identity)
# 2. Generate channel artifacts (sc-genesis-block.proto.bin, not standard genesis.block)
# 3. Start committer-test-node and wait for it to be healthy
# 4. Start FSC endorser nodes
# 5. Register namespace with fxconfig (required before any token operations)

set -e

NETWORK_NAME="fabricx"
CHANNEL_NAME="mychannel"
NAMESPACE="token_namespace"

echo "==> Step 1: Generate crypto material"
# Uses Fabric-X custom cryptogen — NOT standard hyperledger/fabric-tools
# crypto-config.yaml must include Hostname: SC for sidecar identity cert
# Without SC cert, committer-test-node cannot establish MSP identity
docker run --rm \
  -v "$(pwd)/crypto-config.yaml:/config/crypto-config.yaml" \
  -v "$(pwd)/crypto:/output" \
  fabric-x-tools cryptogen generate \
    --config=/config/crypto-config.yaml \
    --output=/output

echo "==> Step 2: Generate channel artifacts"
# Uses Fabric-X custom configtxgen
# Output is sc-genesis-block.proto.bin — NOT standard genesis.block
docker run --rm \
  -v "$(pwd)/configtx.yaml:/config/configtx.yaml" \
  -v "$(pwd):/output" \
  fabric-x-tools configtxgen \
    -profile FabricXGenesis \
    -channelID "$CHANNEL_NAME" \
    -outputBlock /output/sc-genesis-block.proto.bin

echo "==> Step 3: Start committer-test-node"
docker-compose up -d committer-test-node

echo "==> Waiting for committer sidecar to be healthy on :4001..."
until docker-compose exec committer-test-node nc -z localhost 4001 2>/dev/null; do
  echo "   sidecar not ready yet, retrying in 3s..."
  sleep 3
done
echo "   committer sidecar is up"

echo "==> Step 4: Start FSC endorser nodes"
docker-compose up -d endorser1 endorser2

echo "==> Waiting for endorser1 FSC API on :9300..."
until curl -sf http://localhost:9300/healthz > /dev/null 2>&1; do
  echo "   endorser1 not ready yet, retrying in 3s..."
  sleep 3
done
echo "   endorser1 is up"

echo "==> Step 5: Register namespace with fxconfig"
# fxconfig is a Fabric-X specific tool — no equivalent in standard Fabric
# Must be run after committer is healthy and before any token operations
docker run --rm \
  -v "$(pwd)/crypto:/crypto" \
  fabric-x-tools fxconfig namespace create \
    --channel "$CHANNEL_NAME" \
    --namespace "$NAMESPACE" \
    --orderer localhost:7050

echo "==> Verifying namespace is visible..."
until docker run --rm \
  -v "$(pwd)/crypto:/crypto" \
  fabric-x-tools fxconfig namespace list \
    --channel "$CHANNEL_NAME" \
    --orderer localhost:7050 | grep -q "$NAMESPACE"; do
  echo "   namespace not visible yet, retrying in 3s..."
  sleep 3
done

echo ""
echo "==> Fabric-X network is up"
echo "    Committer sidecar : localhost:4001"
echo "    Orderer            : localhost:7050"
echo "    Query service      : localhost:7001"
echo "    Endorser1 API      : localhost:9300"
echo "    Endorser2 API      : localhost:9400"
